import { useEffect } from "react";

export default function StaticPageMotion() {
  useEffect(() => {
    const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    const scopes = Array.from(document.querySelectorAll<HTMLElement>(".calchive-static-motion"));
    const observers: IntersectionObserver[] = [];
    const cleanups: Array<() => void> = [];

    scopes.forEach((scope) => {
      scope.classList.add("calchive-motion-ready");

      const selector = [
        "h1",
        "h2",
        "h3",
        "p",
        "article",
        "aside",
        "form",
        ".bg-card",
        "[data-scroll-reveal]",
      ].join(",");

      const elements = Array.from(new Set(Array.from(scope.querySelectorAll<HTMLElement>(selector))))
        .filter((element) => {
          if (element.closest("[data-no-scroll-motion]")) return false;

          const isText = element.matches("h3, p");
          const isInsideAnimatedCard = Boolean(element.closest(".bg-card, article, aside, form"));
          return !(isText && isInsideAnimatedCard);
        });

      elements.forEach((element, index) => {
        element.classList.add("calchive-reveal");
        element.style.setProperty("--reveal-delay", `${Math.min((index % 7) * 38, 228)}ms`);

        if (element.matches(".bg-card, .rounded-2xl, .rounded-3xl, article, aside")) {
          element.classList.add("calchive-reveal-pop");
        } else if (index % 5 === 1) {
          element.classList.add("calchive-reveal-left");
        } else if (index % 5 === 2) {
          element.classList.add("calchive-reveal-right");
        }
      });

      if (reduceMotion || !("IntersectionObserver" in window)) {
        elements.forEach((element) => element.classList.add("calchive-reveal-in"));
        return;
      }

      let ticking = false;
      const revealVisible = () => {
        ticking = false;
        const viewportLimit = window.innerHeight * 0.92;
        elements.forEach((element) => {
          if (element.classList.contains("calchive-reveal-in")) return;
          const rect = element.getBoundingClientRect();
          if (rect.top < viewportLimit && rect.bottom > 0) {
            element.classList.add("calchive-reveal-in");
          }
        });
      };
      const queueReveal = () => {
        if (ticking) return;
        ticking = true;
        window.requestAnimationFrame(revealVisible);
      };

      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add("calchive-reveal-in");
              observer.unobserve(entry.target);
            }
          });
        },
        { rootMargin: "0px 0px -10% 0px", threshold: 0.08 }
      );

      elements.forEach((element) => observer.observe(element));
      observers.push(observer);
      queueReveal();
      window.addEventListener("scroll", queueReveal, { passive: true });
      window.addEventListener("resize", queueReveal, { passive: true });
      cleanups.push(() => {
        window.removeEventListener("scroll", queueReveal);
        window.removeEventListener("resize", queueReveal);
      });
    });

    return () => {
      observers.forEach((observer) => observer.disconnect());
      cleanups.forEach((cleanup) => cleanup());
    };
  }, []);

  return (
    <style>{`
      .calchive-static-motion {
        animation: calchivePageRise 380ms cubic-bezier(.22,1,.36,1) both;
      }

      .calchive-motion-ready.calchive-reveal,
      .calchive-motion-ready .calchive-reveal {
        opacity: 0;
        transform: translate3d(0, 22px, 0) scale(.992);
        transition:
          opacity 560ms cubic-bezier(.22,1,.36,1),
          transform 560ms cubic-bezier(.22,1,.36,1),
          box-shadow 220ms ease,
          border-color 220ms ease,
          background-color 220ms ease;
        transition-delay: var(--reveal-delay, 0ms);
        will-change: opacity, transform;
      }

      .calchive-motion-ready.calchive-reveal-left,
      .calchive-motion-ready .calchive-reveal-left {
        transform: translate3d(-18px, 18px, 0) scale(.992);
      }

      .calchive-motion-ready.calchive-reveal-right,
      .calchive-motion-ready .calchive-reveal-right {
        transform: translate3d(18px, 18px, 0) scale(.992);
      }

      .calchive-motion-ready.calchive-reveal-pop,
      .calchive-motion-ready .calchive-reveal-pop {
        transform: translate3d(0, 20px, 0) scale(.972);
      }

      .calchive-motion-ready.calchive-reveal-in,
      .calchive-motion-ready .calchive-reveal-in,
      .calchive-motion-ready.calchive-reveal-in.calchive-reveal-left,
      .calchive-motion-ready .calchive-reveal-in.calchive-reveal-left,
      .calchive-motion-ready.calchive-reveal-in.calchive-reveal-right,
      .calchive-motion-ready .calchive-reveal-in.calchive-reveal-right,
      .calchive-motion-ready.calchive-reveal-in.calchive-reveal-pop,
      .calchive-motion-ready .calchive-reveal-in.calchive-reveal-pop {
        opacity: 1;
        transform: translate3d(0, 0, 0) scale(1);
      }

      .calchive-static-motion :where(a, button, .group) {
        transition-property: transform, box-shadow, border-color, background-color, color, opacity;
        transition-duration: 180ms;
        transition-timing-function: cubic-bezier(.22,1,.36,1);
      }

      .calchive-static-motion :where(a:hover, button:hover, .group:hover) {
        transform: translateY(-1px);
      }

      @keyframes calchivePageRise {
        from { opacity: 0; transform: translateY(10px); }
        to { opacity: 1; transform: translateY(0); }
      }

      @media (max-width: 640px) {
        .calchive-static-motion {
          animation-duration: 240ms;
        }

        .calchive-motion-ready.calchive-reveal,
        .calchive-motion-ready .calchive-reveal,
        .calchive-motion-ready.calchive-reveal-left,
        .calchive-motion-ready .calchive-reveal-left,
        .calchive-motion-ready.calchive-reveal-right,
        .calchive-motion-ready .calchive-reveal-right,
        .calchive-motion-ready.calchive-reveal-pop,
        .calchive-motion-ready .calchive-reveal-pop {
          transform: translate3d(0, 14px, 0) scale(.988);
          transition-duration: 360ms;
          transition-delay: min(var(--reveal-delay, 0ms), 120ms);
        }

        .calchive-static-motion :where(a:hover, button:hover, .group:hover) {
          transform: none;
        }

      }

      @media (prefers-reduced-motion: reduce) {
        .calchive-static-motion,
        .calchive-motion-ready.calchive-reveal,
        .calchive-motion-ready .calchive-reveal,
        .calchive-motion-ready.calchive-reveal-left,
        .calchive-motion-ready .calchive-reveal-left,
        .calchive-motion-ready.calchive-reveal-right,
        .calchive-motion-ready .calchive-reveal-right,
        .calchive-motion-ready.calchive-reveal-pop,
        .calchive-motion-ready .calchive-reveal-pop {
          animation: none !important;
          transition: none !important;
          opacity: 1 !important;
          transform: none !important;
          will-change: auto !important;
        }
      }
    `}</style>
  );
}
